 54	void nfapi_pnf_phy_config_delete_all(nfapi_pnf_config_t* config)
 55	{
 56		nfapi_pnf_phy_config_t* curr = config->phys;
 57		while(curr != 0)
 58		{
 59			nfapi_pnf_phy_config_t* to_delete = curr;
 60			curr = curr->next;
 61			free(to_delete);
 62		}
 63	
 64		config->phys = 0;
 65	}
 66	
 67	void nfapi_pnf_phy_config_add(nfapi_pnf_config_t* config, nfapi_pnf_phy_config_t* phy)
 68	{
 69		phy->next = config->phys;
 70		config->phys = phy;
 71	}
