 73	nfapi_pnf_phy_config_t* nfapi_pnf_phy_config_find(nfapi_pnf_config_t* config, uint16_t phy_id)
 74	{
 75		nfapi_pnf_phy_config_t* curr = config->phys;
 76		while(curr != 0)
 77		{
 78			if(curr->phy_id == phy_id)
 79				return curr;
 80	
 81			curr = curr->next;
 82		}
 83		return 0;
 84	}
