 86	void pnf_nr_handle_pnf_param_request(pnf_t* pnf, void *pRecvMsg, int recvMsgLen)
 87	{
 88		// ensure it's valid
 89		if (pRecvMsg == NULL || pnf == NULL)
 90		{
 91			NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s: NULL parameters\n", __FUNCTION__);
 92		}
 93		else
 94		{
 95			nfapi_nr_pnf_param_request_t req;
 96	
 97			NFAPI_TRACE(NFAPI_TRACE_INFO, "PNF_PARAM.request received\n");
 98	
 99			// unpack the message
100			if (nfapi_nr_p5_message_unpack(pRecvMsg, recvMsgLen, &req, sizeof(nfapi_nr_pnf_param_request_t), &pnf->_public.codec_config) >= 0)
101			{
102				if(pnf->_public.state == NFAPI_PNF_IDLE)
103				{
104					if(pnf->_public.pnf_nr_param_req)
105					{
106						(pnf->_public.pnf_nr_param_req)(&pnf->_public, &req);
107					}
108				}
109				else
110				{
111					NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s: PNF not in IDLE state\n", __FUNCTION__);
112	
113					nfapi_nr_pnf_param_response_t resp;
114					memset(&resp, 0, sizeof(resp));
115					resp.header.message_id = NFAPI_NR_PHY_MSG_TYPE_PNF_PARAM_RESPONSE;
116					resp.error_code = NFAPI_MSG_INVALID_STATE;
117					nfapi_nr_pnf_pnf_param_resp(&pnf->_public, &resp);
118				}
119			}
120			else
121			{
122				NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s: Unpack message failed, ignoring\n", __FUNCTION__);
123			}
124	
125			if(req.vendor_extension)
126				pnf->_public.codec_config.deallocate(req.vendor_extension);
127		}
128	}
